def test_forbidden_role_cannot_update_org_announcement(api_client, existing_announcement, viewer_auth_token):
    ann_id = existing_announcement["id"]
    payload = {"title": "Viewer attempt", "body": "Should be forbidden"}
    resp = api_client.put(
        f"/org-announcements/{ann_id}",
        json=payload,
        headers={"Authorization": f"Bearer {viewer_auth_token}"}
    )
    assert resp.status_code == 403, f"Expected 403 for viewer role, got {resp.status_code}"
    err = resp.json()
    assert "error" in err or "message" in err, "Response should contain error detail"
